INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '03a3845d-07e3-44a1-9982-7ade227217b8',
  '00000000-0000-0000-0000-000000000001',
  $escape$iam Zero Trust Architecture — Always Verify Microsegments$escape$,
  $escape$To enforce zero trust in iam, create a microsegmented architecture by defining granular IAM policies. Use iam's Conditions feature to specify IP ranges, user attributes, and resource properties. For example, allow access to a specific S3 bucket only when the request originates from a trusted IP range: `{ "Version": "2012-10-17", "Statement": [ { "Effect": "Allow", "Action": "s3:GetObject", "Resource": "arn:aws:s3:::example-bucket/*", "Condition": { "IpAddress": { "aws:SourceIp": [ "192.0.2.1/32" ] } } } ] }`$escape$,
  NULL,
  NULL,
