INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '139ab391-9bf9-4126-a5a1-4d879867f40d',
  '00000000-0000-0000-0000-000000000001',
  $escape$IAM: Detecting Misconfigurations at Scale with IAM Cloud Security Posture$escape$,
  $escape$IAM provides a built-in feature called Cloud Security Posture, which utilizes AWS Config to track and monitor resource configurations. You can leverage AWS Config Rules to detect and remediate misconfigurations at scale. To create a Config Rule in IAM, use the `CreateConfigRule` API. The rule can be triggered by a specific resource or a service-linked role. You can also define a threshold to trigger remediation actions.$escape$,
  $escape$const iam = new AWS.IAM();
const params = {
  ConfigRule: {
    Name: 'CSPM-Rule',
    Description: 'CSPM Rule',
    InputParameters: {
      Threshold: 1
    }
  }
};
iam.createConfigRule(params, (err, data) => {
  if (err) console.log(err);
  else console.log(data);
});$escape$,
  $escape$typescript$escape$,
