INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '36d82073-31cb-426a-83bf-9db54d08b26f',
  '00000000-0000-0000-0000-000000000001',
  $escape$iam: Enforcing Pod Security Standards with Falco$escape$,
  $escape$To ensure container security in iam, you can leverage Falco's runtime security capabilities. Start by installing the Falco operator in your iam cluster: `oc apply -f https://raw.githubusercontent.com/falcosecurity/falco-operator/main/deploy/operator.yaml`. Then, configure the Falco operator to monitor your pods using the `falco-config` CR: `oc apply -f - <<EOF`.
`apiVersion: falco.org/v1alpha1
kind: FalcoConfig
metadata:
  name: falco-config
spec:
  rules:  - selector: {}
    output: allow
    severity: LOW
    desc: 'allow all pods'
EOF`.
This allows Falco to monitor your pods and enforce pod security standards.$escape$,
  $escape$oc apply -f - <<EOF
apiVersion: falco.org/v1alpha1
kind: FalcoConfig
metadata:
  name: falco-config
spec:
  rules:  - selector: {}
    output: allow
    severity: LOW
    desc: 'allow all pods'
EOF$escape$,
  $escape$bash$escape$,
